var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`그 날 법정은 어둡고, 공기는 차가웠어.`,JPN:`あの日の法廷は暗くて、空気は冷たかったわ。`,ENG:`That day, the court room was dark and the air was cold.`,TWN:`那天法院裡很黑，空氣很冰冷。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`보호소로 데리고 가는 임시 보호자의 손은 무척 딱딱했고.`,JPN:`私を保護所に連れていく臨時保護者の手はとても硬くて。`,ENG:`The hands of my temporary guardian felt stiff and cold as she took me to the orphanage.`,TWN:`帶我去育幼院的臨時監護人手很僵硬。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`narration`,speaker:null,text:{KOREA:`내가 의지할 데는 아무데도 없었어.`,JPN:`私が頼るところはどこにもいなかった。`,ENG:`There was no one I could rely on.`,TWN:`我失去一切依靠。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`narration`,speaker:null,text:{KOREA:`집에서 들고 나온 그 여자의 액션 피규어만 빼고.`,JPN:`家から持ってきた、あの女のアクションフィギュア以外には。`,ENG:`Except for the action figure of that woman that I brought from home.`,TWN:`只剩從家裡帶出來的那女人的公仔。`},stage:{bg:`CHARADE_001`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`허억……! 헉……!`,JPN:`はあ……！　はあっ……！`,ENG:`*Huff…!* *Huff…!*`,TWN:`呼呼……！呼……！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`눈이 적응되고 있어. 이제 야투경이 없어도 돼…….`,JPN:`目が適応してる。もうナイトビジョンがなくても大丈夫……`,ENG:`I'm starting to get used to the darkness. I don't need night vision goggles anymore...`,TWN:`眼睛正在習慣黑暗，現在不需要夜視鏡了……`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RIFLE_CHARADE_NULL_C`,text:{KOREA:`빌어먹을 꼬맹이가 더럽게 끈질기네.`,JPN:`クソガキが、しつこいな。`,ENG:`The damn kid is persistent.`,TWN:`該死的小鬼真難纏。`},stage:{bg:`BLACK`,slots:{L:{char_id:`RIFLE_CHARADE_NULL_D`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_CHARADE_NULL_C`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`RIFLE_CHARADE_NULL_D`,text:{KOREA:`비켜. 방탄복이 없는 데를 노려야지.`,JPN:`どけ。防弾服がないところを狙わないと。`,ENG:`Move. You have to aim for the part between the armor.`,TWN:`走開，要瞄準沒穿防彈衣的地方才行。`},stage:{bg:`BLACK`,slots:{L:{char_id:`RIFLE_CHARADE_NULL_D`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_CHARADE_NULL_C`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`RIFLE_CHARADE_NULL_D`,text:{KOREA:`개머리판을… 이렇게 말이야!`,JPN:`銃床を……こうやってな！`,ENG:`Use the stock... like this!`,TWN:`用槍托……這樣！`},stage:{bg:`BLACK`,slots:{L:{char_id:`RIFLE_CHARADE_NULL_D`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_CHARADE_NULL_C`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`아악!!`,JPN:`あぁあっ！`,ENG:`Aaah!`,TWN:`啊啊！！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`꼬맹이!`,JPN:`おこちゃま！`,ENG:`Kid!`,TWN:`小鬼！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L19_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`아윽…… 윽……`,JPN:`あうっ……くうっ……`,ENG:`Aah... Urgh...`,TWN:`唔呃……呃……`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_DESPAIR`},R:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`RIFLE_CHARADE_NULL_D`,text:{KOREA:`꼬마야, 하늘이 노랗게 보이지?`,JPN:`ガキ、目の前がぼんやりするだろ？`,ENG:`The world's spinning, kid, ain't it?`,TWN:`小鬼，是不是眼前一片黑？`},stage:{bg:`BLACK`,slots:{L:{char_id:`RIFLE_CHARADE_NULL_D`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_CHARADE_NULL_C`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`RIFLE_CHARADE_NULL_D`,text:{KOREA:`조금만 참아라. 번지 점프 한 번 뛰면 편해질 테니까.`,JPN:`もう少し我慢しろよな。バンジージャンプをしたら楽になるぞ。`,ENG:`Hold on just a little longer. One bungee jump and you'll be at peace.`,TWN:`再忍一下，再來個高空彈跳就好囉。`},stage:{bg:`BLACK`,slots:{L:{char_id:`RIFLE_CHARADE_NULL_D`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_CHARADE_NULL_C`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`콜록……! 이거, 놔……!`,JPN:`ゲホッ……！　離し、て……！`,ENG:`*Cough...!* Let me... go!`,TWN:`咳咳……！放開，我……！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`번지 점프는 댁 혼자 뛰셔. 얘는 키가 작아서 못 하걸랑.`,JPN:`バンジージャンプは一人でやれよ。こいつは背が低くてできないからな。`,ENG:`Save the jump for yourselves. She's too short to bungee jump anyway.`,TWN:`要跳你自己去跳！她太矮不能跳。`},stage:{bg:`BLACK`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};